use std::collections::HashMap;
use serde::{Serialize, Deserialize};

#[derive(Debug, Serialize, Deserialize)]
struct RoomMapping {
    room_name: String,
    users: Vec<String>,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let config_data = "user1 roomAnuser2 roomBnuser3 roomAnuser4 roomAnuser5 roomBn";
    let mut room_to_users: HashMap<String, Vec<String>> = HashMap::new();

    for line in config_data.trim().lines() {
        let parts: Vec<&str> = line.split_whitespace().collect();
        if parts.len() == 2 {
            let user_id = parts[0].to_string();
            let room_name = parts[1].to_string();
            room_to_users.entry(room_name).or_default().push(user_id);
        }
    }

    let mut mappings: Vec<RoomMapping> = Vec::new();
    for (room_name, users) in room_to_users {
        mappings.push(RoomMapping {
            room_name: room_name.to_string(),
            users: users.clone(),
        });
    }

    let json_output = serde_json::to_string_pretty(&mappings)?;
    println!("{}", json_output);

    Ok(())
}

use std::collections::HashMap;
use std::io::{self, Write};

struct SchemaDefinition {
    table_name: String,
    columns: HashMap<String, String>,
}

impl SchemaDefinition {
    fn build(table_name: &str, raw_definitions: &[&str]) -> io::Result<Self> {
        let mut columns = HashMap::new();
        for definition in raw_definitions.iter().take(1).skip(1) { 
            if !definition.is_empty() { 
                let parts: Vec<&str> = definition.split_whitespace().collect();
                if parts.len() >= 2 {
                    let name = parts[0].to_string();
                    let type_str = &parts[1];
                    columns.insert(name, type_str.to_string());
                }
            }
        }
        Ok(SchemaDefinition {
            table_name: table_name.to_string(),
            columns,
        })
    }
}

fn main() -> io::Result<()> {
    let schema_tokens = vec![
        "CREATE TABLE", 
        "users", 
        "id INT PRIMARY KEY", 
        "username VARCHAR NOT NULL"
    ];

    match SchemaDefinition::build("users", &schema_tokens) {
        Ok(definition) => {
            println!("Successfully parsed schema for table: {}", definition.table_name);
            for (col, typ) in &definition.columns {
                println!("  - Column '{}' has type: {}", col, typ);
            }
        },
        Err(e) => {
            eprintln!("Error parsing schema: {}", e);
        }
    }
    Ok(())
}

use std::collections::HashMap;

struct Record {
    id: u32,
    name: String,
    value: f64,
}

fn process_data(input: &str) -> HashMap<u32, Record> {
    let mut map = HashMap::new();
    for line in input.lines() {
        if line.trim().is_empty() { continue; }
        let parts: Vec<&str> = line.split(",").collect();
        if parts.len() != 3 {
            continue;
        }

        match (parts[0].parse::<u32>(), parts[1].to_string(), parts[2].parse::<f64>()) {
            (Ok(id), name, Ok(value)) => {
                let record = Record { id, name, value };
                map.insert(id, record);
            }
            _ => { 
            }
        }
    }
    map
}

use std::collections::HashSet;
use std::env;

fn check_file_existence(paths: &str) -> Result<HashSet<String>, String> {
    let path_tokens: Vec<&str> = paths.split(',').collect();
    let mut found_paths = HashSet::new();

    for token in path_tokens { 
        if !token.trim().is_empty() {
            let full_path = env::temp_dir().join(token.trim());
            if full_path.exists() && full_path.is_file() {
                found_paths.insert(full_path.to_string_lossy().into_owned());
            } else {
                return Err(format!("Path does not exist or is not a file: {}", token.trim()));
            }
        }
    }
    Ok(found_paths)
}

fn main() {
    let test_paths = "./nonexistent_file, stdlib/path.rs";
    match check_file_existence(test_paths) {
        Ok(paths) => println!("Successfully validated paths: {:?}", paths),
        Err(e) => eprintln!("Validation Error: {}", e),
    }
}

use std::collections::HashMap;

struct DataPoint {
    key: String,
    metadata: Vec<f64>,
}

fn aggregate_data(input_stream: &[&str]) -> HashMap<String, f64> {
    let mut results: HashMap<String, f64> = HashMap::new();
    for i in (0..input_stream.len()).step_by(2) { 
        if let (Some(key_token), Some(value_token)) = (input_stream.get(i), input_stream.get(i + 1)) {
            let key_str: String = key_token.to_string();
            if let Ok(value) = value_token.parse::<f64>() {
                let entry = results.entry(key_str).or_insert(0.0);
                *entry += value;
            }
        }
    }
    results
}
